[
  {
    "file": "packages/features/feature-opt-in/config.ts",
    "line": 76,
    "severity": "critical",
    "description": "The isFeatureAllowedForScope function crashes when config.scope is undefined. The interface defines scope as optional (scope?: OptInFeatureScope[]), and the comment states 'Features without a scope field are allowed for all scopes.' However, the function attempts to call .includes() on undefined, causing a TypeError. All other functions in the file (getOptInFeaturesForScope, HAS_USER_OPT_IN_FEATURES, etc.) correctly handle this with '!f.scope || f.scope.includes(scope)' pattern.",
    "fix_patch": "--- a/packages/features/feature-opt-in/config.ts
+++ b/packages/features/feature-opt-in/config.ts
@@ -73,7 +73,7 @@ export function getOptInFeaturesForScope(scope: OptInFeatureScope): OptInFeature
 export function isFeatureAllowedForScope(slug: string, scope: OptInFeatureScope): boolean {
   const config = getOptInFeatureConfig(slug);
   if (!config) return false;
-  return config.scope.includes(scope);
+  return !config.scope || config.scope.includes(scope);
 }
"
  },
  {
    "file": "packages/features/feature-opt-in/services/FeatureOptInService.ts",
    "line": 205,
    "severity": "critical",
    "description": "The listFeaturesForUser method has an inverted filter condition. The JSDoc comment at line 187 states it should return features that are 'globally enabled', but the filter on line 205 uses '!state.globalEnabled' which returns globally DISABLED features. This is backwards and contradicts the semantics of the listFeaturesForTeam method (line 240) which correctly filters with 'result.globalEnabled' (without negation).",
    "fix_patch": "--- a/packages/features/feature-opt-in/services/FeatureOptInService.ts
+++ b/packages/features/feature-opt-in/services/FeatureOptInService.ts
@@ -202,6 +202,6 @@ export class FeatureOptInService implements IFeatureOptInService {
       featureIds,
     });

-    return featureIds.map((featureId) => resolvedStates[featureId]).filter((state) => !state.globalEnabled);
+    return featureIds.map((featureId) => resolvedStates[featureId]).filter((state) => state.globalEnabled);
   }

"
  },
  {
    "file": "packages/trpc/server/routers/viewer/featureOptIn/_router.ts",
    "line": 95,
    "severity": "high",
    "description": "The setUserState mutation endpoint (lines 88-104) is missing slug validation against the opt-in allowlist, while the equivalent setTeamState (line 117) and setOrganizationState (line 146) endpoints both include 'if (!isOptInFeature(input.slug))' validation. This is a compliance violation—inconsistent error handling and validation pattern across mutation endpoints. Invalid slugs should be caught early in the router with a TRPCError, not delegated to the service.",
    "fix_patch": "--- a/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
+++ b/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
@@ -93,6 +93,13 @@ export const featureOptInRouter = router({
     })
     .mutation(async ({ ctx, input }) => {
+      if (!isOptInFeature(input.slug)) {
+        throw new TRPCError({
+          code: "BAD_REQUEST",
+          message: "Invalid slug. This feature is not opt-in configurable.",
+        });
+      }
+
       await featureOptInService.setUserFeatureState({
         userId: ctx.user.id,
         featureId: input.slug,
"
  }
]

